import{_ as e,o as i,c as a,ag as t}from"./chunks/framework.BbyMWZAR.js";const k=JSON.parse('{"title":"错误处理机制","description":"","frontmatter":{"title":"错误处理机制","difficulty":"medium","tags":["错误处理","Promise","EventEmitter"],"estimate":20},"headers":[],"relativePath":"domains/nodejs/qa/qa-07-error-handling.md","filePath":"domains/nodejs/qa/qa-07-error-handling.md","lastUpdated":1783504823000}'),r={name:"domains/nodejs/qa/qa-07-error-handling.md"};function n(o,s,l,d,h,c){return i(),a("div",null,[...s[0]||(s[0]=[t('<h1 id="问答-07-进阶-错误处理机制" tabindex="-1">问答 07（进阶）：错误处理机制 <a class="header-anchor" href="#问答-07-进阶-错误处理机制" aria-label="Permalink to &quot;问答 07（进阶）：错误处理机制&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>Node.js 中有哪些错误处理方式？同步、回调、Promise/async、EventEmitter、以及未捕获异常应如何处理？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>几类错误处理</strong></p><ol><li><strong>同步代码</strong>：<code>try/catch</code>。</li><li><strong>回调风格（error-first callback）</strong>：约定回调第一个参数是 <code>err</code>，如 <code>fs.readFile(path, (err, data) =&gt; {...})</code>，必须先判断 <code>err</code>。</li><li><strong>Promise / async-await</strong>：<code>.catch()</code> 或 <code>try/catch</code> 包裹 <code>await</code>。</li><li><strong>EventEmitter</strong>：监听 <code>&#39;error&#39;</code> 事件。<strong>未监听 <code>error</code> 事件的 EventEmitter 抛错会导致进程崩溃</strong>。</li><li><strong>Stream</strong>：本质是 EventEmitter，用 <code>pipeline</code> 或监听 <code>error</code>。</li></ol><p><strong>进程级兜底</strong></p><ul><li><code>process.on(&#39;uncaughtException&#39;, handler)</code>：捕获未被处理的同步/回调异常。</li><li><code>process.on(&#39;unhandledRejection&#39;, handler)</code>：捕获未 catch 的 Promise。</li></ul><p><strong>重要原则</strong></p><ul><li><code>uncaughtException</code> <strong>只应用于记录日志 + 优雅退出</strong>，不应假装无事继续运行——此时进程状态可能已损坏，继续运行会有不可预期行为。正确做法是记录、释放资源、<code>process.exit(1)</code>，交给进程管理器（PM2/k8s）重启。</li><li>业务错误应在尽量靠近发生处捕获处理，兜底只是最后防线。</li></ul><h2 id="追问-1-async-函数里忘记-await-一个会-reject-的-promise-会怎样" tabindex="-1">追问 1：<code>async</code> 函数里忘记 <code>await</code> 一个会 reject 的 Promise 会怎样？ <a class="header-anchor" href="#追问-1-async-函数里忘记-await-一个会-reject-的-promise-会怎样" aria-label="Permalink to &quot;追问 1：`async` 函数里忘记 `await` 一个会 reject 的 Promise 会怎样？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>该 Promise 变成「未处理的拒绝」，触发 <code>unhandledRejection</code>。较新 Node 版本默认会打印警告，甚至以非零码退出进程（<code>--unhandled-rejections=throw</code> 是默认）。</li><li>典型场景：<code>someAsync()</code> 单独一行没有 <code>await</code> 也没 <code>.catch()</code>。</li><li>解决：要么 <code>await</code>，要么显式 <code>.catch()</code>，要么确实是「即发即忘」也应加 <code>.catch(logError)</code>。</li></ul><h2 id="追问-2-express-里如何统一处理-async-路由抛出的错误" tabindex="-1">追问 2：Express 里如何统一处理 async 路由抛出的错误？ <a class="header-anchor" href="#追问-2-express-里如何统一处理-async-路由抛出的错误" aria-label="Permalink to &quot;追问 2：Express 里如何统一处理 async 路由抛出的错误？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>Express 4 的路由<strong>不会自动捕获 async 函数中 reject 的错误</strong>，需要手动 <code>try/catch</code> 后 <code>next(err)</code>，或用包装器：</li></ul><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wrap</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> fn</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">req</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">res</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">next</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Promise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(req, res, next)).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(next);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/x&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">async</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">req</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">res</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 抛错会被 next 捕获 */</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }));</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li>然后用错误处理中间件（4 个参数）统一处理：<code>app.use((err, req, res, next) =&gt; {...})</code>。</li><li>Express 5 已内置对返回 Promise 的路由的错误捕获。</li></ul><h2 id="追问-3-如何设计一个生产级的错误分类与响应策略" tabindex="-1">追问 3：如何设计一个生产级的错误分类与响应策略？ <a class="header-anchor" href="#追问-3-如何设计一个生产级的错误分类与响应策略" aria-label="Permalink to &quot;追问 3：如何设计一个生产级的错误分类与响应策略？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>区分可预期错误（operational）与程序 bug（programmer error）</strong>：前者如参数校验失败、资源不存在、第三方超时，应返回合适状态码并降级；后者是代码缺陷，应记录并可能重启。</li><li>自定义错误类（<code>class AppError extends Error</code>）携带 <code>statusCode</code>、<code>code</code>、<code>isOperational</code>。</li><li>统一错误中间件根据类型返回：4xx（客户端错误，不打堆栈到用户）、5xx（服务端错误，记录完整堆栈但对用户屏蔽细节）。</li><li>配合结构化日志（含 requestId/traceId）、监控告警、以及进程管理器自动重启。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/api/errors.html" target="_blank" rel="noreferrer">Node.js: Errors</a>：Error 类型、操作错误与系统错误的分类。</li><li><a href="https://nodejs.org/api/process.html#event-uncaughtexception" target="_blank" rel="noreferrer">Node.js: process: uncaughtException</a>：<code>uncaughtException</code>/<code>unhandledRejection</code> 官方建议与退出策略。</li><li><a href="https://nodejs.org/api/events.html" target="_blank" rel="noreferrer">Node.js: events</a>：EventEmitter <code>error</code> 事件未监听导致进程崩溃的行为。</li></ul>',24)])])}const g=e(r,[["render",n]]);export{k as __pageData,g as default};
